import { useState, useEffect } from 'react';
import { Container, Card, Stack, Row, Text, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface ForecastDay {
  day: string;
  condition: string;
  icon: string;
  highTemp: number;
  lowTemp: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  icon?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: 'C' | 'F';
  forecast?: ForecastDay[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Partly Cloudy',
  icon = '⛅',
  humidity = 65,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', condition: 'Sunny', icon: '☀️', highTemp: 75, lowTemp: 62 },
    { day: 'Tue', condition: 'Cloudy', icon: '☁️', highTemp: 68, lowTemp: 59 },
    { day: 'Wed', condition: 'Rainy', icon: '🌧️', highTemp: 62, lowTemp: 54 },
    { day: 'Thu', condition: 'Sunny', icon: '☀️', highTemp: 73, lowTemp: 60 },
    { day: 'Fri', condition: 'Partly Cloudy', icon: '⛅', highTemp: 74, lowTemp: 61 },
  ],
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();
  const scaleInAnimation = motionEnabled ? animation.scaleIn : 'none';
  const fadeInAnimation = motionEnabled ? animation.fadeIn : 'none';
  const slideInUpAnimation = motionEnabled ? animation.slideInUp : 'none';

  const getAnimationDelay = (index: number): string => {
    if (!motionEnabled) return '0ms';
    const ms = index * 50;
    return ms + 'ms';
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-md, 16px)">
      <MotionKeyframes />

      <Card shadow="md" padding="var(--ggui-spacing-lg, 24px)">
        <Stack direction="vertical" gap={24}>

          {/* Header with City Name */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            paddingBottom: 'var(--ggui-spacing-md, 16px)',
            borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)',
          }}>
            <Text 
              variant="h2"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="bold"
            >
              {city}
            </Text>
            <Text 
              variant="body"
              color="var(--ggui-color-text-secondary, #6b7280)"
            >
              Today
            </Text>
          </div>

          {/* Current Weather Section */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: 'var(--ggui-spacing-lg, 24px)',
            alignItems: 'center',
            padding: 'var(--ggui-spacing-md, 16px)',
            backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
            borderRadius: 'var(--ggui-radius-lg, 12px)',
            animation: fadeInAnimation,
          }}>
            {/* Temperature Display */}
            <div style={{
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-sm, 8px)',
            }}>
              <div style={{
                fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
                lineHeight: 1.2,
              }}>
                {temperature}°{unit}
              </div>
              <Text 
                variant="body"
                color="var(--ggui-color-text-primary, #111827)"
                weight="medium"
              >
                {condition}
              </Text>
              <Text 
                variant="caption"
                color="var(--ggui-color-text-secondary, #6b7280)"
              >
                Feels like {Math.round(temperature * 0.95)}°{unit}
              </Text>
            </div>

            {/* Weather Icon */}
            <div style={{
              fontSize: 'clamp(60px, 15vw, 120px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              animation: scaleInAnimation,
            }}>
              {icon}
            </div>
          </div>

          {/* Current Conditions Stats */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: 'var(--ggui-spacing-md, 16px)',
          }}>
            {/* Humidity */}
            <div style={{
              padding: 'var(--ggui-spacing-md, 16px)',
              backgroundColor: 'var(--ggui-color-surface, #ffffff)',
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              borderRadius: 'var(--ggui-radius-md, 8px)',
              textAlign: 'center',
            }}>
              <Text 
                variant="caption"
                color="var(--ggui-color-text-secondary, #6b7280)"
                weight="medium"
              >
                Humidity
              </Text>
              <div style={{
                fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
                marginTop: 'var(--ggui-spacing-xs, 4px)',
              }}>
                {humidity}%
              </div>
            </div>

            {/* Wind Speed */}
            <div style={{
              padding: 'var(--ggui-spacing-md, 16px)',
              backgroundColor: 'var(--ggui-color-surface, #ffffff)',
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              borderRadius: 'var(--ggui-radius-md, 8px)',
              textAlign: 'center',
            }}>
              <Text 
                variant="caption"
                color="var(--ggui-color-text-secondary, #6b7280)"
                weight="medium"
              >
                Wind Speed
              </Text>
              <div style={{
                fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
                marginTop: 'var(--ggui-spacing-xs, 4px)',
              }}>
                {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
              </div>
            </div>
          </div>

          <Divider margin={8} />

          {/* 5-Day Forecast Header */}
          <Text 
            variant="h3"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>

          {/* Forecast Strip */}
          <div style={{
            display: 'flex',
            gap: 'var(--ggui-spacing-sm, 8px)',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-xs, 4px)',
            scrollBehavior: 'smooth',
            WebkitOverflowScrolling: 'touch',
          }}>
            {forecast.map((day, index) => (
              <div
                key={day.day + index}
                style={{
                  flex: '0 0 auto',
                  minWidth: 'clamp(80px, 18vw, 120px)',
                  padding: 'var(--ggui-spacing-md, 16px)',
                  backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                  borderRadius: 'var(--ggui-radius-md, 8px)',
                  textAlign: 'center',
                  transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                  cursor: 'pointer',
                  animation: slideInUpAnimation,
                  animationDelay: getAnimationDelay(index),
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.backgroundColor = 'var(--ggui-color-primary-100, #e0f2fe)';
                  e.currentTarget.style.boxShadow = 'var(--ggui-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.backgroundColor = 'var(--ggui-color-primary-50, #f0f9ff)';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                <Text 
                  variant="label"
                  color="var(--ggui-color-primary-700, #0369a1)"
                  weight="semibold"
                >
                  {day.day}
                </Text>

                <div style={{
                  fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                  margin: 'var(--ggui-spacing-xs, 4px) 0',
                }}>
                  {day.icon}
                </div>

                <Text 
                  variant="caption"
                  color="var(--ggui-color-text-secondary, #6b7280)"
                >
                  {day.condition}
                </Text>

                <div style={{
                  marginTop: 'var(--ggui-spacing-xs, 4px)',
                  display: 'flex',
                  justifyContent: 'center',
                  gap: 'var(--ggui-spacing-xs, 4px)',
                  alignItems: 'center',
                }}>
                  <Text 
                    variant="caption"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    weight="semibold"
                  >
                    {day.highTemp}°
                  </Text>
                  <Text 
                    variant="caption"
                    color="var(--ggui-color-text-secondary, #6b7280)"
                  >
                    {day.lowTemp}°
                  </Text>
                </div>
              </div>
            ))}
          </div>

          {/* Footer info */}
          <Text 
            variant="caption"
            color="var(--ggui-color-text-secondary, #6b7280)"
            align="center"
          >
            Last updated: {new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          </Text>
        </Stack>
      </Card>
    </Container>
  );
}
